css:
.aurora {
  background: linear-gradient(135deg, #0f0c29, #302b63);
  position: relative;
  overflow: hidden;
}
.aurora::before, .aurora::after {
  content: '';
  position: absolute;
  border-radius: 50%;
  filter: blur(60px);
  mix-blend-mode: screen;
  animation: aurora-shift 8s ease infinite alternate;
}
.aurora::before { width: 300px; height: 300px; background: rgba(184,251,60,0.3); top: -100px; left: -100px; }
.aurora::after { width: 250px; height: 250px; background: rgba(168,85,247,0.4); bottom: -80px; right: -80px; animation-delay: -4s; }
@keyframes aurora-shift {
  0% { transform: translate(0,0) scale(1); }
  100% { transform: translate(40px,40px) scale(1.2); }
}

.mesh-bg {
  background-color: #0f0c29;
  background-image:
    radial-gradient(at 40% 20%, rgba(184,251,60,0.15) 0px, transparent 50%),
    radial-gradient(at 80% 0%, rgba(168,85,247,0.2) 0px, transparent 50%),
    radial-gradient(at 0% 50%, rgba(6,182,212,0.15) 0px, transparent 50%);
}

.neon-bg {
  background:
    radial-gradient(ellipse at top left, rgba(184,251,60,0.12) 0%, transparent 60%),
    radial-gradient(ellipse at bottom right, rgba(6,182,212,0.12) 0%, transparent 60%),
    #050508;
}

.holo-bg {
  background: linear-gradient(-45deg, #ff0080, #ff4500, #ffff00, #00ff80, #0080ff, #8000ff, #ff0080);
  background-size: 400% 400%;
  animation: holo-shift 6s ease infinite;
}
@keyframes holo-shift {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

.spotlight-bg {
  background: radial-gradient(ellipse at center, rgba(184,251,60,0.15) 0%, rgba(184,251,60,0.05) 30%, transparent 70%), #050508;
}

.light-gradient-bg {
  background: linear-gradient(135deg, rgba(255,255,255,0.9) 0%, rgba(240,240,255,0.8) 50%, rgba(225,225,255,0.7) 100%);
  backdrop-filter: blur(40px);
}

.noise-bg {
  position: relative;
  background: linear-gradient(135deg, #1a1a3e, #0f0f2e);
}
.noise-bg::after {
  content: '';
  position: absolute;
  inset: 0;
  background-image: url("data:image/svg+xml,...");
  pointer-events: none;
}

.animated-diagonal {
  background: linear-gradient(-45deg, #0f0c29, #302b63, #24243e, #0f3460);
  background-size: 400% 400%;
  animation: diagonal-shift 8s ease infinite;
}
@keyframes diagonal-shift {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}
